__CPROVER_assigns(*score)
// every output cell is still a valid exponent: a merge increments a cell at most once
__CPROVER_ensures(__CPROVER_forall {
	int _k;
	(0 <= _k && _k < SIZE) ==> ((const uint8_t *)array)[_k] <= 30
})
