#include <stdio.h>
#include <stdbool.h>
#include <stdint.h>
#define SIZE 4
uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop){
  uint8_t t;
  if (x==0) return x;
  for(t=x-1;;t--){
    if(array[t]!=0){
      if(array[t]!=array[x]) return t+1;
      return t;
    } else { if(t==stop) return t; }
  }
  return x;
}
bool slideArray(uint8_t array[SIZE], uint32_t *score){
  bool success=false; uint8_t x,t,stop=0;
  for(x=0;x<SIZE;x++){
    if(array[x]!=0){
      t=findTarget(array,x,stop);
      if(t!=x){
        if(array[t]==0) array[t]=array[x];
        else if(array[t]==array[x]){ array[t]++; *score+=1<<array[t]; stop=t+1; }
        array[x]=0; success=true;
      }
    }
  }
  return success;
}
void rotateBoard(uint8_t board[SIZE][SIZE]){
  uint8_t i,j,n=SIZE,tmp;
  for(i=0;i<n/2;i++) for(j=i;j<n-i-1;j++){
    tmp=board[i][j];
    board[i][j]=board[j][n-i-1];
    board[j][n-i-1]=board[n-i-1][n-j-1];
    board[n-i-1][n-j-1]=board[n-j-1][i];
    board[n-j-1][i]=tmp;
  }
